{"output":"import { Button } from '@chakra-ui/react';
import {
  SocialProvider,
  SupportProfileFormValues,
} from '@pages/Settings/pages/accountSetup/OrganizationInfo/OrgDetailsForm/WebsiteSocialFormFields/types';
import { useFormContext, UseFormGetValues, UseFormWatch } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { AddIcon } from '@ui/assets/icons/AddIcon';
import { DeleteIcon } from '@ui/assets/icons/DeleteIcon';
import { toTitleCase } from '@utils';
import { DropdownWithTextbox } from '../formControls/DropdownWithTextboxControl';
import { FieldArray } from '../formControls/FieldArray';

const SOCIAL_PROVIDERS = Object.values(SocialProvider);

function determineUsedSocialProviders(watch: UseFormWatch<SupportProfileFormValues>) {
  return new Set(watch('social').map((x) => x.provider));
}

function determineRemainingDropdownOptions(
  getValues: UseFormGetValues<SupportProfileFormValues>,
  idx: number,
  takenSocials: Set<SocialProvider>
) {
  const fieldValue = getValues().social[idx].provider;
  const fieldDropdownOptions = SOCIAL_PROVIDERS.filter(
    (provider) => provider === fieldValue || !takenSocials.has(provider)
  ).map((provider) => ({ label: toTitleCase(provider), value: provider }));
  return fieldDropdownOptions;
}

export const SocialProfiles = () => {
  const { t } = useTranslation('supportProfile');

  const { getValues, watch } = useFormContext<SupportProfileFormValues>();

  const takenSocials = determineUsedSocialProviders(watch);

  return (
    <FieldArray name="social">
      {({ append, fields, remove }) => (
        <>
          {fields.map((field, idx) => {
            const fieldDropdownOptions = determineRemainingDropdownOptions(
              getValues as unknown as UseFormGetValues<SupportProfileFormValues>,
              idx,
              takenSocials
            );

            return (
              <DropdownWithTextbox
                actionClick={() => remove(idx)}
                actionIcon={<DeleteIcon />}
                actionLabel={t('aria.removeSocialProvider')}
                dropdownLabel={t('label.socialProviderDropdown')}
                dropdownName={`social.${idx}.provider`}
                dropdownOptions={fieldDropdownOptions}
                dropdownPlaceholder="-"
                key={field.id}
                textboxLabel="URL"
                textboxName={`social.${idx}.url`}
              />
            );
          })}
          {takenSocials.size < SOCIAL_PROVIDERS.length && (
            <Button
              borderColor="neutral.600"
              leftIcon={<AddIcon />}
              onClick={() =>
                append({
                  provider: undefined,
                  url: '',
                })
              }
              variant="outline"
              w="full"
            >
              {t('button.addSocialProvider')}
            </Button>
          )}
        </>
      )}
    </FieldArray>
  );
};
