{"output":"import { useCallback, useMemo, useState } from 'react';
import { Flex } from '@chakra-ui/react';
import { OrganizationInformation } from '@pages/components/OrganizationInformation/OrganizationInformation';
import { useTranslation } from 'react-i18next';
import {
  useGetAccountConfiguration,
  useUpdateAccountConfiguration,
} from '@state/accountConfiguration';
import { useGetAccount, useUpdateAccount } from '@state/accounts';
import { useGetAddresses } from '@state/addresses';
import { ActionBar, ContainerWithActionBar } from '@ui/components/ActionBar';
import { VerticalScrollContainer } from '@ui/components/Containers';
import { Loading } from '@ui/components/Loading';
import { SettingsContainer, SettingsSubmit } from '@ui/components/Settings';
import { useToast } from '@ui/components/Toast';
import { Form } from '@ui/components/formControls/Form';
import { formatName } from '@ui/utils';
import { ChangeOwner } from './ChangeOwner/ChangeOwner';
import {
  PointsOfContactFormFields,
  PointsOfContactFormFieldValues,
  SocialProvider,
  usePointsOfContactFormFieldSchema,
  useWebsiteSocialFormFieldSchema,
  WebsiteSocialFormFields,
  WebsiteSocialFormFieldValues,
} from './OrgDetailsForm';

const FORM_ID = 'org-info-form';

type FormValues = WebsiteSocialFormFieldValues & PointsOfContactFormFieldValues;

export const OrganizationInfo = () => {
  const [isChangingOwner, setIsChangingOwner] = useState(false);
  // TODO: setIsChangingOwner via Points of Contact

  const { t } = useTranslation(['common', 'settings']);

  const { currentAccount } = useGetAccount();
  const { accountConfiguration } = useGetAccountConfiguration();

  const { addresses } = useGetAddresses({
    accountId: currentAccount?.id,
    options: {
      types: ['legal', 'physical', 'mailing', 'other'],
    },
  });

  const initialValues = useMemo<FormValues>(
    () => ({
      donorContactId: accountConfiguration?.donorContact?.id ?? undefined,
      financialContactId: accountConfiguration?.financialContact?.id ?? undefined,
      marketingContactId: accountConfiguration?.marketingContact?.id ?? undefined,
      primaryContactId: accountConfiguration?.primaryContact?.id ?? undefined,
      social: [
        {
          provider: SocialProvider.Website,
          url: currentAccount?.url ?? '',
        },
        {
          provider: SocialProvider.Twitter,
          url: currentAccount?.twitter ?? '',
        },
        {
          provider: SocialProvider.Facebook,
          url: currentAccount?.facebook ?? '',
        },
        {
          provider: SocialProvider.Instagram,
          url: currentAccount?.instagram ?? '',
        },
      ].filter((x) => !!x.url),
    }),
    [currentAccount, accountConfiguration]
  );

  const {
    error: updateAccountError,
    isLoading: isUpdatingAccount,
    updateAccountAsync,
  } = useUpdateAccount({ shouldShowToast: false });
  const {
    accountConfigurationUpdateError,
    isUpdatingAccountConfiguration: isUpdatingPointsOfContact,
    updateAccountConfigurationAsync,
  } = useUpdateAccountConfiguration();
  const { showToast } = useToast();
  const handleSubmit = useCallback(
    async ({ social, ...contactIds }: FormValues) => {
      const updateAccountTask = updateAccountAsync({
        updates: {
          facebook: social.find((x) => x.provider === 'facebook')?.url ?? null,
          instagram: social.find((x) => x.provider === 'instagram')?.url ?? null,
          twitter: social.find((x) => x.provider === 'twitter')?.url ?? null,
          url: social.find((x) => x.provider === 'website')?.url ?? null,
        },
      });

      // Ensure that fields are undefined for unselected contacts
      const updateAccountConfigurationTask = updateAccountConfigurationAsync({
        donorContactId: contactIds.donorContactId || null,
        financialContactId: contactIds.financialContactId || null,
        marketingContactId: contactIds.marketingContactId || null,
        primaryContactId: contactIds.primaryContactId || null,
      });

      try {
