          message: t('settings:organizationInfo.state.updateSuccess'),
          variant: 'success',
        });
      } catch {
        showToast({
          message: t('settings:organizationInfo.state.updateFailure'),
          variant: 'error',
        });
      }
    },
    [t, updateAccountAsync, updateAccountConfigurationAsync, showToast]
