import { InputProps } from '@chakra-ui/react';
import { useControl } from '../hooks/useControl';
import { InputControl, InputControlProps } from './InputControl';

export type FormInputControlProps = Overwrite<
  InputControlProps,
  { debounce?: number; name: string; transformValue?: (value: string) => string }
>;

export const FormInputControl = forwardRef<HTMLInputElement, FormInputControlProps>(
  ({ formControlProps, inputGroupProps, name, transformValue, ...props }, ref) => {
    const { error, field, invalid } = useControl({ name });

    const handleOnChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      e.target.value = transformValue ? transformValue(e.target.value) : e.target.value;
      field.onChange(e);
    };

    const transformProps: InputProps = transformValue
      ? {
          onChange: handleOnChange,
        }
      : {};

    return (
      <InputControl
        {...props}
        {...field}
        formControlProps={{
          error,
          mb: props.type === 'hidden' ? 0 : 2,
          mt: props.type === 'hidden' ? 0 : undefined,
          ...formControlProps,
        }}
        inputGroupProps={{
          sx: props.type === 'hidden' ? { marginTop: '0px !important' } : undefined,
          ...inputGroupProps,
        }}
        isInvalid={invalid}
        {...transformProps}
        ref={ref}
      />
    );
  }
);
